package com.google.gson.internal;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  @Test
  void write_CallsTypeAdaptersJsonElementWrite() throws IOException {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> typeAdaptersMockedStatic = Mockito.mockStatic(TypeAdapters.class)) {
      var jsonElementAdapter = mock(TypeAdapters.JSON_ELEMENT.getClass());
      // Since TypeAdapters.JSON_ELEMENT is a static final field of type TypeAdapter<JsonElement>,
      // we must mock the write method on it. But it's a field, not a method, so we mock the field's class.
      // Instead, we can spy on TypeAdapters.JSON_ELEMENT directly.

      // Spy on TypeAdapters.JSON_ELEMENT
      var jsonElementAdapterSpy = spy(TypeAdapters.JSON_ELEMENT);
      typeAdaptersMockedStatic.when(() -> TypeAdapters.JSON_ELEMENT).thenReturn(jsonElementAdapterSpy);

      // Call the method under test
      Streams.write(element, writer);

      // Verify that TypeAdapters.JSON_ELEMENT.write(writer, element) was called
      verify(jsonElementAdapterSpy).write(writer, element);
    }
  }
}
